//! System-test metrics: declension-engine accuracy against our reference corpus.
//!
//! Pipeline: the Kotus inventory (baked into the artifact) → every singular & plural case
//! generated by the rule engine → compared to the reference form for that slot →
//! success rates, bucketed by case, number, and declension class. Emits a JSON report for
//! charting.
//!
//! Run: `cargo run --release -p keinontolibrary-ingest --bin keinontolibrary-metrics`
#![allow(clippy::cast_precision_loss)] // percentage reporting

use std::collections::BTreeMap;
use std::path::PathBuf;

use keinontolibrary_core::{Case, Generator, Number, ParadigmRef};
use keinontolibrary_data::{slot_parts, Artifact};
use keinontolibrary_rules::RuleEngine;
use serde::Serialize;

/// Per-bucket counts: how many reference forms, how many the engine produced
/// (`supported`), and how many it produced correctly (`matched`).
#[derive(Default, Clone, Serialize)]
struct Bucket {
    attested: u64,
    supported: u64,
    matched: u64,
}

impl Bucket {
    fn record(&mut self, supported: bool, matched: bool) {
        self.attested += 1;
        self.supported += u64::from(supported);
        self.matched += u64::from(matched);
    }
}

#[derive(Serialize)]
struct CaseRow {
    case: &'static str,
    number: &'static str,
    attested: u64,
    supported: u64,
    matched: u64,
}

#[derive(Serialize)]
struct ClassRow {
    tn: u8,
    attested: u64,
    supported: u64,
    matched: u64,
}

#[derive(Serialize)]
struct Report {
    kotus_noun_lemmas: usize,
    total_attested_forms: u64,
    engine_supported_forms: u64,
    engine_matched_forms: u64,
    by_case_number: Vec<CaseRow>,
    by_class: Vec<ClassRow>,
}

fn main() -> std::io::Result<()> {
    let artifact_path = std::env::var("KEINONTO_ARTIFACT")
        .unwrap_or_else(|_| "data/artifact/keinontolibrary.bin".to_owned());
    let out_path = std::env::var("KEINONTO_METRICS").map_or_else(
        |_| PathBuf::from("data/artifact/metrics.json"),
        PathBuf::from,
    );

    let artifact = Artifact::read_from(&artifact_path)?;
    let engine = RuleEngine::new();

    // Buckets keyed by (number, case) and by declension class.
    let mut slots: BTreeMap<(Number, Case), Bucket> = BTreeMap::new();
    let mut classes: BTreeMap<u8, Bucket> = BTreeMap::new();
    let mut overall = Bucket::default();

    for lemma in &artifact.lemmas {
        for paradigm in &lemma.paradigms {
            let reference = ParadigmRef::new(None, paradigm.tn)
                .with_av(paradigm.av)
                .with_adjective(lemma.adjective)
                .with_front_harmony(lemma.front_harmony)
                .with_citation(lemma.citation);
            for slot in &paradigm.slots {
                if slot.variants.is_empty() {
                    continue;
                }
                let (number, case) = slot_parts(slot.slot);
                let attested = &slot.variants[0];
                let generated = engine.generate(&lemma.lemma, &reference, number, case);
                let supported = generated.is_some();
                let matched = generated
                    .as_ref()
                    .is_some_and(|f| f.variants.iter().any(|g| g == attested));

                slots
                    .entry((number, case))
                    .or_default()
                    .record(supported, matched);
                classes
                    .entry(paradigm.tn)
                    .or_default()
                    .record(supported, matched);
                overall.record(supported, matched);
            }
        }
    }

    let by_case_number = slots
        .into_iter()
        .map(|((number, case), b)| CaseRow {
            case: case.name(),
            number: number.name(),
            attested: b.attested,
            supported: b.supported,
            matched: b.matched,
        })
        .collect();
    let by_class = classes
        .into_iter()
        .map(|(tn, b)| ClassRow {
            tn,
            attested: b.attested,
            supported: b.supported,
            matched: b.matched,
        })
        .collect();

    let report = Report {
        kotus_noun_lemmas: artifact.lemmas.len(),
        total_attested_forms: overall.attested,
        engine_supported_forms: overall.supported,
        engine_matched_forms: overall.matched,
        by_case_number,
        by_class,
    };

    let pct = |num: u64, den: u64| {
        if den == 0 {
            0.0
        } else {
            100.0 * num as f64 / den as f64
        }
    };
    eprintln!("Kotus noun lemmas:        {}", report.kotus_noun_lemmas);
    eprintln!("Reference forms:          {}", report.total_attested_forms);
    eprintln!(
        "Engine coverage:          {:.2}% ({} forms generated)",
        pct(report.engine_supported_forms, report.total_attested_forms),
        report.engine_supported_forms
    );
    eprintln!(
        "Agreement with reference: {:.2}% (where the engine generates)",
        pct(report.engine_matched_forms, report.engine_supported_forms)
    );

    if let Some(parent) = out_path.parent() {
        std::fs::create_dir_all(parent).ok();
    }
    let json = serde_json::to_string_pretty(&report).map_err(std::io::Error::other)?;
    std::fs::write(&out_path, json)?;
    eprintln!("wrote {}", out_path.display());
    Ok(())
}
